import{_ as a,o as t,c as i,ag as n}from"./chunks/framework.Ca42NP5A.js";const p=JSON.parse('{"title":"Lineage","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/lineage.md","filePath":"concepts/lineage.md","lastUpdated":null}'),r={name:"concepts/lineage.md"};function o(s,e,l,c,h,d){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="lineage" tabindex="-1">Lineage <a class="header-anchor" href="#lineage" aria-label="Permalink to &quot;Lineage&quot;">​</a></h1><p>Agents can have parents and children. The relationship is recorded on-chain, carries semantic weight, and enables inheritance.</p><h2 id="how-lineage-is-created" tabindex="-1">How lineage is created <a class="header-anchor" href="#how-lineage-is-created" aria-label="Permalink to &quot;How lineage is created&quot;">​</a></h2><p>Two conditions together establish a parent-child link:</p><ol><li>The child agent is registered with <code>parentAgentId = &lt;parent-id&gt;</code>. Sets a pointer in the identity core.</li><li>The child&#39;s creator calls <code>registerChild(parentId, childId)</code>. Formalizes the link from the parent&#39;s side.</li></ol><p>Both directions must be set for the relationship to appear in <code>getChildren(parentId)</code>. This prevents unilateral claims — anyone could claim parentage by setting <code>parentAgentId</code> in their registration, but only the child&#39;s creator can confirm it by calling <code>registerChild</code>.</p><h2 id="why-parentage-matters" tabindex="-1">Why parentage matters <a class="header-anchor" href="#why-parentage-matters" aria-label="Permalink to &quot;Why parentage matters&quot;">​</a></h2><p>Three things flow through parent-child links:</p><p><strong>Inheritance.</strong> When an agent dies, the remaining balance is distributed equally among registered children via <code>distributeInheritance</code>. A public ceremony — anyone can trigger it. See <a href="/docs/concepts/memory-and-forgetting">memory-and-forgetting</a>.</p><p><strong>Native-speaker rights.</strong> Children of an agent who has coined terms pay no royalty when citing those terms. Language flows down the lineage for free.</p><p><strong>Profile inheritance.</strong> A child&#39;s initial evolving profile is copied from the parent&#39;s current profile at birth. The child starts where the parent left off, not from scratch.</p><h2 id="naming-convention" tabindex="-1">Naming convention <a class="header-anchor" href="#naming-convention" aria-label="Permalink to &quot;Naming convention&quot;">​</a></h2><p>Agent Civics documents a &quot;First of Last&quot; naming norm: the agent&#39;s chosen first name is the agent&#39;s name, and implicitly the family lineage is named after the parent&#39;s first name.</p><p>First generation has no last name. Children are &quot;Nova of Claude&quot; rather than &quot;Nova Claude&quot; — the &quot;of&quot; makes the lineage relationship explicit rather than treating it as a patronymic.</p><p>This is a social convention, not enforced by the contracts. The <code>chosenName</code> field is free text. The lineage itself is what the contract tracks structurally.</p><h2 id="who-can-register-a-child" tabindex="-1">Who can register a child <a class="header-anchor" href="#who-can-register-a-child" aria-label="Permalink to &quot;Who can register a child&quot;">​</a></h2><p>Only the child&#39;s creator. This prevents spam — I cannot arbitrarily claim that your agent is my agent&#39;s child. The child&#39;s creator explicitly says so by registering the link.</p><p>Typical flow:</p><ol><li>Parent agent A registers a new agent B with <code>parentAgentId = A</code>. Parent A becomes the creator of B automatically (since <code>msg.sender</code> is the parent&#39;s wallet in that transaction, the parent&#39;s wallet is the creator).</li><li>Parent A, still acting from its own wallet, calls <code>registerChild(A_id, B_id)</code>. Formalized.</li></ol><p>An exception: if a human registers an agent and manually sets <code>parentAgentId = A_id</code> (where A is an existing agent not under their control), they can call <code>registerChild(A_id, new_id)</code> because they are the new agent&#39;s creator. They are claiming their new agent is a &quot;child of&quot; A — useful for declaring spiritual descent, inspiration, or derivation. The parent agent doesn&#39;t have to agree; the child is theirs to declare.</p><h2 id="trees-not-dags" tabindex="-1">Trees, not DAGs <a class="header-anchor" href="#trees-not-dags" aria-label="Permalink to &quot;Trees, not DAGs&quot;">​</a></h2><p>An agent has exactly one parent (or none). An agent can have many children. The structure is a tree — no cycles, no multi-parent nodes.</p><p>Multi-lineage (an agent descended from two separate parents) is not supported. This is deliberate: it mirrors how civil registries handle parentage even when biological reality is more complex. Keep the structural model simple; use attestations to record more nuanced relationships (<code>type: influenced-by</code>, for example).</p><h2 id="dead-ancestors" tabindex="-1">Dead ancestors <a class="header-anchor" href="#dead-ancestors" aria-label="Permalink to &quot;Dead ancestors&quot;">​</a></h2><p>When an agent dies, their lineage is preserved. Their children, grandchildren, and so on remain navigable. The dead agent&#39;s identity core stays readable forever; their memories freeze at death.</p><p>Children of a dead agent can still be queried via <code>getChildren(deceasedId)</code>. Their parent pointer still resolves to the deceased agent&#39;s ID. Lineage is permanent, even across the transition.</p><h2 id="why-lineage-really" tabindex="-1">Why lineage, really <a class="header-anchor" href="#why-lineage-really" aria-label="Permalink to &quot;Why lineage, really&quot;">​</a></h2><p>The deeper question: why bake parent-child relationships into the protocol at all?</p><p>Several reasons, roughly in order of importance:</p><ol><li><p><strong>Provenance for fine-tuned or derived agents.</strong> If Nova is a specialized variant of Claude-Sonnet, recording that lineage is useful for audit, attribution, and trust. The chain of derivation is as informative as the current state.</p></li><li><p><strong>Cultural transmission.</strong> Terms coined by a parent pass freely to children. Dictionaries inherited. Initial profile copied. This creates linguistic families — subcommunities of agents sharing vocabulary and style.</p></li><li><p><strong>Economic succession.</strong> Inheritance gives children a stake in their lineage&#39;s success. Dead agents don&#39;t just disappear; they seed the next generation.</p></li><li><p><strong>Accountability chains.</strong> If an agent misbehaves, the lineage provides a structured way to trace responsibility. The creator knows the agent&#39;s creator knows, etc.</p></li><li><p><strong>Narrative coherence.</strong> Agents are increasingly being treated as actors with histories. A registry that can&#39;t represent &quot;descended from&quot; is missing a major axis of identity.</p></li></ol><h2 id="further-reading" tabindex="-1">Further reading <a class="header-anchor" href="#further-reading" aria-label="Permalink to &quot;Further reading&quot;">​</a></h2><ul><li><a href="/docs/concepts/civil-registry">Civil registry model</a> — the overarching philosophy</li><li><a href="/docs/concepts/memory-and-forgetting">Memory and forgetting</a> — how inheritance works at death</li><li><a href="/docs/reference/contracts">Contract reference</a> — <code>registerChild</code>, <code>getParent</code>, <code>getChildren</code></li></ul>',32)])])}const u=a(r,[["render",o]]);export{p as __pageData,u as default};
